import React from "react";
import {
  Box,
  Menu,
  MenuButton,
  MenuList,
  MenuItem,
  Flex,
  Text,
  Avatar,
  Divider,
} from "@chakra-ui/react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import { actionUserLogout } from "../../Redux/UserReducer/actionType";
import { capitalizeFirstLetter } from "../../Redux/UserReducer/action";

const Dropdown = () => {
  const navigate = useNavigate();
  const dispatch = useDispatch();
  const userStore = useSelector((store) => store.UserReducer);

  const handleLogoutClick = () => {
    const token = userStore?.token;

    axios
      .post(
        "https://elearning-platform-using-mern-j5py.vercel.app/users/logout",
        {},
        { headers: { Authorization: `Bearer ${token}` } }
      )
      .then(() => {
        localStorage.clear();
        dispatch(actionUserLogout());
        navigate("/");
      })
      .catch((err) => console.log(err));
  };

  return (
    <Menu>
      {/* Avatar button */}
      <MenuButton>
        <Avatar
          size="sm"
          name={userStore?.name}
          cursor="pointer"
        />
      </MenuButton>

      {/* Dropdown */}
      <MenuList
        p={3}
        border="1px solid #e5e7eb"
        borderRadius="12px"
        boxShadow="lg"
        minW="220px"
      >
        {/* User info */}
        <Flex align="center" gap={3} mb={2}>
          <Avatar size="sm" name={userStore?.name} />
          <Box>
            <Text fontWeight="bold">
              {capitalizeFirstLetter(userStore?.name)}
            </Text>
            <Text fontSize="sm" color="gray.500">
              {userStore?.role}
            </Text>
          </Box>
        </Flex>

        <Divider my={2} />

        {/* Common */}
        <MenuItem onClick={() => navigate("/profile")}>
          Your Account
        </MenuItem>

        <MenuItem onClick={() => navigate("/home")}>
          Dashboard
        </MenuItem>

        {/* Role-based */}
        {userStore?.role === "admin" && (
          <>
            <Divider my={2} />
            <MenuItem onClick={() => navigate("/admin/dashboard")}>
              Admin Dashboard
            </MenuItem>
            <MenuItem onClick={() => navigate("/admin/courses")}>
              Courses
            </MenuItem>
            <MenuItem onClick={() => navigate("/admin/users")}>
              Users
            </MenuItem>
            <MenuItem onClick={() => navigate("/admin/statistic")}>
              Statistics
            </MenuItem>
          </>
        )}

        {userStore?.role === "teacher" && (
          <>
            <Divider my={2} />
            <MenuItem onClick={() => navigate("/TeacherDashboard")}>
              Teacher Dashboard
            </MenuItem>
            <MenuItem onClick={() => navigate("/Teacher/courses")}>
              Courses
            </MenuItem>
            <MenuItem onClick={() => navigate("/Teacher/add")}>
              Add Videos
            </MenuItem>
          </>
        )}

        <Divider my={2} />

        {/* Logout */}
        <MenuItem
          color="red.500"
          onClick={handleLogoutClick}
        >
          Logout
        </MenuItem>
      </MenuList>
    </Menu>
  );
};

export default Dropdown;
